// ============================================================================
// LineIndex - Empty/Initial State
// ============================================================================

TEST(line_index_empty) {
    LineIndex index;
    TEST_ASSERT_EQ(index.line_count(), 0u);
    TEST_ASSERT_TRUE(index.empty());
}

TEST(line_index_build_null) {
    LineIndex index;
    index.build(nullptr);
    TEST_ASSERT_EQ(index.line_count(), 0u);
}

TEST(line_index_clear) {
    PieceTable pt;
    pt.init_from_string("line1\nline2", 11);
    LineIndex index;
    index.build(&pt);
    TEST_ASSERT_EQ(index.line_count(), 2u);
    index.clear();
    TEST_ASSERT_EQ(index.line_count(), 0u);
}

// ============================================================================
// LineIndex - Build from PieceTable
// ============================================================================

TEST(line_index_build_empty_doc) {
    PieceTable pt;
    LineIndex index;
    index.build(&pt);
    // Empty doc still has "1 line" conceptually but piece table has 0 length
    TEST_ASSERT_EQ(index.line_count(), 1u);
}

TEST(line_index_build_single_line) {
    PieceTable pt;
    pt.init_from_string("hello world", 11);
    LineIndex index;
    index.build(&pt);

    TEST_ASSERT_EQ(index.line_count(), 1u);
    const LineEntry* line = index.get_line(1);
    TEST_ASSERT_NOT_NULL(line);
    TEST_ASSERT_EQ(line->byte_offset, 0u);
    TEST_ASSERT_EQ(line->line_number, 1u);
}

TEST(line_index_build_two_lines) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    LineIndex index;
    index.build(&pt);

    TEST_ASSERT_EQ(index.line_count(), 2u);

    const LineEntry* line1 = index.get_line(1);
    TEST_ASSERT_NOT_NULL(line1);
    TEST_ASSERT_EQ(line1->byte_offset, 0u);

    const LineEntry* line2 = index.get_line(2);
    TEST_ASSERT_NOT_NULL(line2);
    TEST_ASSERT_EQ(line2->byte_offset, 6u);  // After "hello\n"
}

TEST(line_index_build_multiple_lines) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3\nline4", 23);
    LineIndex index;
    index.build(&pt);

    TEST_ASSERT_EQ(index.line_count(), 4u);

    TEST_ASSERT_EQ(index.get_line(1)->byte_offset, 0u);
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 6u);
    TEST_ASSERT_EQ(index.get_line(3)->byte_offset, 12u);
    TEST_ASSERT_EQ(index.get_line(4)->byte_offset, 18u);
}

TEST(line_index_build_trailing_newline) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\n", 12);
    LineIndex index;
    index.build(&pt);

    // Trailing newline creates an empty line at the end
    TEST_ASSERT_EQ(index.line_count(), 3u);
    TEST_ASSERT_EQ(index.get_line(3)->byte_offset, 12u);
}

// ============================================================================
// LineIndex - Line Lookups
// ============================================================================

TEST(line_index_get_line_out_of_range) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    LineIndex index;
    index.build(&pt);

    // Line 0 is invalid (1-indexed)
    TEST_ASSERT_NULL(index.get_line(0));

    // Line 3 is out of range
    TEST_ASSERT_NULL(index.get_line(3));

    // Line 100 is out of range
    TEST_ASSERT_NULL(index.get_line(100));
}

TEST(line_index_get_line_valid) {
    PieceTable pt;
    pt.init_from_string("aaa\nbb\nc", 8);
    LineIndex index;
    index.build(&pt);

    const LineEntry* line1 = index.get_line(1);
    const LineEntry* line2 = index.get_line(2);
    const LineEntry* line3 = index.get_line(3);

    TEST_ASSERT_NOT_NULL(line1);
    TEST_ASSERT_NOT_NULL(line2);
    TEST_ASSERT_NOT_NULL(line3);

    TEST_ASSERT_EQ(line1->byte_offset, 0u);
    TEST_ASSERT_EQ(line2->byte_offset, 4u);
    TEST_ASSERT_EQ(line3->byte_offset, 7u);
}

// ============================================================================
// LineIndex - Viewport Calculations
// ============================================================================

TEST(line_index_first_visible_no_scroll) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3\nline4\nline5", 29);
    LineIndex index;
    index.build(&pt);
    index.set_line_height(20.0f);

    // At scroll 0, first visible line is 1
    TEST_ASSERT_EQ(index.first_visible_line(0.0f), 1u);
}

TEST(line_index_first_visible_scrolled) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3\nline4\nline5", 29);
    LineIndex index;
    index.build(&pt);
    index.set_line_height(20.0f);

    // Scroll 40px = 2 lines, first visible is line 3
    TEST_ASSERT_EQ(index.first_visible_line(40.0f), 3u);

    // Scroll 50px = 2.5 lines, first visible is line 3 (partial)
    TEST_ASSERT_EQ(index.first_visible_line(50.0f), 3u);

    // Scroll 60px = 3 lines, first visible is line 4
    TEST_ASSERT_EQ(index.first_visible_line(60.0f), 4u);
}

TEST(line_index_last_visible) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3\nline4\nline5", 29);
    LineIndex index;
    index.build(&pt);
    index.set_line_height(20.0f);

    // Viewport 60px = 3 lines, last visible is 4 (for partial visibility)
    size_t last = index.last_visible_line(0.0f, 60.0f);
    TEST_ASSERT_TRUE(last >= 3u && last <= 4u);
}

TEST(line_index_visible_line_count) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3\nline4\nline5", 29);
    LineIndex index;
    index.build(&pt);
    index.set_line_height(20.0f);

    // 100px viewport with 20px lines = 5 lines + 2 for partials = 7, clamped to 5
    size_t count = index.visible_line_count(100.0f);
    TEST_ASSERT_EQ(count, 5u);

    // 40px viewport = 2 lines + 2 = 4
    count = index.visible_line_count(40.0f);
    TEST_ASSERT_EQ(count, 4u);
}

TEST(line_index_total_content_height) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3", 17);
    LineIndex index;
    index.build(&pt);
    index.set_line_height(20.0f);

    // 3 lines * 20px = 60px
    TEST_ASSERT_EQ(index.total_content_height(), 60.0f);
}

// ============================================================================
// LineIndex - Byte to Line Lookup
// ============================================================================

TEST(line_index_byte_to_line_first_line) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    LineIndex index;
    index.build(&pt);

    // Byte 0-5 are in line 1
    TEST_ASSERT_EQ(index.byte_to_line(0), 1u);
    TEST_ASSERT_EQ(index.byte_to_line(3), 1u);
    TEST_ASSERT_EQ(index.byte_to_line(5), 1u);  // newline char is still line 1
}

TEST(line_index_byte_to_line_second_line) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    LineIndex index;
    index.build(&pt);

    // Byte 6-10 are in line 2
    TEST_ASSERT_EQ(index.byte_to_line(6), 2u);
    TEST_ASSERT_EQ(index.byte_to_line(10), 2u);
}

TEST(line_index_byte_to_line_multiple_lines) {
    PieceTable pt;
    pt.init_from_string("aaa\nbb\nc", 8);
    LineIndex index;
    index.build(&pt);

    // Line 1: bytes 0-3 (aaa\n)
    TEST_ASSERT_EQ(index.byte_to_line(0), 1u);
    TEST_ASSERT_EQ(index.byte_to_line(3), 1u);

    // Line 2: bytes 4-6 (bb\n)
    TEST_ASSERT_EQ(index.byte_to_line(4), 2u);
    TEST_ASSERT_EQ(index.byte_to_line(6), 2u);

    // Line 3: byte 7 (c)
    TEST_ASSERT_EQ(index.byte_to_line(7), 3u);
}

TEST(line_index_byte_to_line_empty) {
    LineIndex index;
    // Empty index should return line 1
    TEST_ASSERT_EQ(index.byte_to_line(0), 1u);
}

// ============================================================================
// LineIndex - Incremental Updates
// ============================================================================

TEST(line_index_update_insert_no_newlines) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    LineIndex index;
    index.build(&pt);

    // Insert "XX" at position 2 (in "hello")
    // No newlines added, so line count stays the same
    index.update_after_insert(2, 2, nullptr, 0);

    TEST_ASSERT_EQ(index.line_count(), 2u);
    // Line 2 offset should increase by 2
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 8u);  // Was 6, now 8
}

TEST(line_index_update_insert_with_newline) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    LineIndex index;
    index.build(&pt);

    // Insert "X\nY" at position 2 (adds 1 newline at relative position 1)
    size_t offsets[] = { 1 };  // '\n' is at byte_pos + 1
    index.update_after_insert(2, 3, offsets, 1);

    TEST_ASSERT_EQ(index.line_count(), 3u);
    // Verify new line starts at correct position: byte_pos + offset + 1 = 2 + 1 + 1 = 4
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 4u);
}

TEST(line_index_update_delete_no_newlines) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    LineIndex index;
    index.build(&pt);

    // Delete 2 chars at position 2 ("ll" from "hello")
    index.update_after_delete(2, 2, 0);

    TEST_ASSERT_EQ(index.line_count(), 2u);
    // Line 2 offset should decrease by 2
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 4u);  // Was 6, now 4
}

TEST(line_index_update_delete_with_newline) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    LineIndex index;
    index.build(&pt);

    // Delete "o\nw" at position 4 (removes 1 newline)
    index.update_after_delete(4, 3, 1);

    TEST_ASSERT_EQ(index.line_count(), 1u);
}

TEST(line_index_update_delete_multiple_newlines) {
    PieceTable pt;
    pt.init_from_string("a\nb\nc\nd", 7);
    LineIndex index;
    index.build(&pt);

    TEST_ASSERT_EQ(index.line_count(), 4u);

    // Delete "b\nc\n" (positions 2-5, 2 newlines)
    index.update_after_delete(2, 4, 2);

    TEST_ASSERT_EQ(index.line_count(), 2u);
}

TEST(line_index_update_complex_sequence) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3", 17);
    LineIndex index;
    index.build(&pt);

    TEST_ASSERT_EQ(index.line_count(), 3u);

    // Insert text without newlines
    index.update_after_insert(0, 5, nullptr, 0);  // "XXXXX" at start
    TEST_ASSERT_EQ(index.line_count(), 3u);

    // Delete a newline
    index.update_after_delete(10, 1, 1);  // Remove first \n
    TEST_ASSERT_EQ(index.line_count(), 2u);
}

TEST(line_index_update_insert_verifies_offsets) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);  // line 1 at 0, line 2 at 6
    LineIndex index;
    index.build(&pt);

    // Insert "X\nY\n" at position 2: newlines at relative positions 1 and 3
    size_t offsets[] = { 1, 3 };
    index.update_after_insert(2, 4, offsets, 2);

    TEST_ASSERT_EQ(index.line_count(), 4u);
    // New line 2 starts at byte_pos + offset + 1 = 2 + 1 + 1 = 4 (after first \n)
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 4u);
    // New line 3 starts at byte_pos + offset + 1 = 2 + 3 + 1 = 6 (after second \n)
    TEST_ASSERT_EQ(index.get_line(3)->byte_offset, 6u);
    // Original line 2 is now line 4, offset shifted by 4 bytes: 6 + 4 = 10
    TEST_ASSERT_EQ(index.get_line(4)->byte_offset, 10u);
}

TEST(line_index_update_delete_boundary_correct) {
    PieceTable pt;
    pt.init_from_string("a\nb\nc", 5);  // line 1 at 0, line 2 at 2, line 3 at 4
    LineIndex index;
    index.build(&pt);

    TEST_ASSERT_EQ(index.line_count(), 3u);
    TEST_ASSERT_EQ(index.get_line(1)->byte_offset, 0u);
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 2u);
    TEST_ASSERT_EQ(index.get_line(3)->byte_offset, 4u);

    // Delete "a\n" (bytes 0-1), which removes 1 newline
    // Line at byte 2 SHOULD be removed because its preceding newline (at byte 1) was deleted
    // Document becomes "b\nc" with lines at bytes 0 and 2
    index.update_after_delete(0, 2, 1);

    TEST_ASSERT_EQ(index.line_count(), 2u);
    // Line 1 is unchanged (at byte 0)
    TEST_ASSERT_EQ(index.get_line(1)->byte_offset, 0u);
    // Line 3 (was at byte 4) is now line 2 at byte 2 (shifted by 2)
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 2u);
}

// ============================================================================
// LineIndex - Edge Cases
// ============================================================================

TEST(line_index_empty_lines) {
    PieceTable pt;
    pt.init_from_string("\n\n\n", 3);  // 3 empty lines + 1 final
    LineIndex index;
    index.build(&pt);

    TEST_ASSERT_EQ(index.line_count(), 4u);
    TEST_ASSERT_EQ(index.get_line(1)->byte_offset, 0u);
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 1u);
    TEST_ASSERT_EQ(index.get_line(3)->byte_offset, 2u);
    TEST_ASSERT_EQ(index.get_line(4)->byte_offset, 3u);
}

TEST(line_index_crlf) {
    PieceTable pt;
    pt.init_from_string("line1\r\nline2\r\n", 14);
    LineIndex index;
    index.build(&pt);

    // We only count \n as line separator
    TEST_ASSERT_EQ(index.line_count(), 3u);
    TEST_ASSERT_EQ(index.get_line(1)->byte_offset, 0u);
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 7u);  // After "line1\r\n"
    TEST_ASSERT_EQ(index.get_line(3)->byte_offset, 14u);
}

TEST(line_index_single_char_lines) {
    PieceTable pt;
    pt.init_from_string("a\nb\nc", 5);
    LineIndex index;
    index.build(&pt);

    TEST_ASSERT_EQ(index.line_count(), 3u);
    TEST_ASSERT_EQ(index.get_line(1)->byte_offset, 0u);
    TEST_ASSERT_EQ(index.get_line(2)->byte_offset, 2u);
    TEST_ASSERT_EQ(index.get_line(3)->byte_offset, 4u);
}

TEST(line_index_zero_line_height) {
    PieceTable pt;
    pt.init_from_string("line1\nline2", 11);
    LineIndex index;
    index.build(&pt);
    index.set_line_height(0.0f);

    // Should handle gracefully without division by zero
    TEST_ASSERT_EQ(index.first_visible_line(100.0f), 1u);
    TEST_ASSERT_EQ(index.visible_line_count(100.0f), 0u);
}

TEST(line_index_negative_scroll) {
    PieceTable pt;
    pt.init_from_string("line1\nline2", 11);
    LineIndex index;
    index.build(&pt);
    index.set_line_height(20.0f);

    // Negative scroll should clamp to first line
    TEST_ASSERT_EQ(index.first_visible_line(-100.0f), 1u);
}

// ============================================================================
// LineIndex - Performance
// ============================================================================

TEST(line_index_performance_100k_lines) {
    // Generate 100K line content
    std::string content;
    content.reserve(3000000);  // Estimate ~30 bytes per line
    for (int i = 0; i < 100000; i++) {
        content += "Line ";
        content += std::to_string(i + 1);
        content += " with some content\n";
    }

    PieceTable pt;
    pt.init_from_string(content.c_str(), content.size());

    LineIndex index;

    auto start = std::chrono::high_resolution_clock::now();
    index.build(&pt);
    auto end = std::chrono::high_resolution_clock::now();

    auto ms = std::chrono::duration_cast<std::chrono::milliseconds>(end - start).count();

    // Must complete in < 20ms
    TEST_ASSERT_TRUE(ms < 20);
    TEST_ASSERT_EQ(index.line_count(), 100001u);  // 100K newlines = 100001 lines

    // Verify O(1) visible range calculation
    index.set_line_height(20.0f);
    TEST_ASSERT_EQ(index.first_visible_line(0.0f), 1u);
    TEST_ASSERT_EQ(index.first_visible_line(1000.0f), 51u);  // 1000 / 20 = 50, +1 for 1-index
}

TEST(line_index_performance_byte_to_line) {
    // Build index with 10K lines
    std::string content;
    for (int i = 0; i < 10000; i++) {
        content += "Line content here\n";
    }

    PieceTable pt;
    pt.init_from_string(content.c_str(), content.size());

    LineIndex index;
    index.build(&pt);

    // Do 10000 byte_to_line lookups
    auto start = std::chrono::high_resolution_clock::now();
    for (int i = 0; i < 10000; i++) {
        size_t offset = (i * 17) % content.size();  // Spread across doc
        volatile size_t line = index.byte_to_line(offset);
        (void)line;
    }
    auto end = std::chrono::high_resolution_clock::now();

    auto us = std::chrono::duration_cast<std::chrono::microseconds>(end - start).count();

    // 10K lookups should complete in < 3ms (< 1us per lookup with binary search)
    TEST_ASSERT_TRUE(us < 3000);
}
